const googleTrends = $('node', 'google-trends-scraper')[0].json;
const blogData = $('node', 'industry-blog-scraper')[0].json;

// Parse Google Trends RSS
const parser = new DOMParser();
const xmlDoc = parser.parseFromString(googleTrends.body, 'text/xml');
const items = xmlDoc.getElementsByTagName('item');

let trends = [];
for (let i = 0; i < Math.min(3, items.length); i++) {
  const title = items[i].getElementsByTagName('title')[0]?.textContent;
  const description = items[i].getElementsByTagName('description')[0]?.textContent;
  if (title) {
    trends.push({
      title: title,
      description: description,
      source: 'Google Trends',
      category: 'trending'
    });
  }
}

// Extract blog headlines (assuming HTML structure)
const blogHTML = blogData.body;
const blogParser = new DOMParser();
const blogDoc = blogParser.parseFromString(blogHTML, 'text/html');
const headlines = blogDoc.querySelectorAll('h1, h2, .post-title, .headline');

for (let i = 0; i < Math.min(2, headlines.length); i++) {
  if (headlines[i]?.textContent) {
    trends.push({
      title: headlines[i].textContent.trim(),
      description: '',
      source: 'Industry Blog',
      category: 'industry'
    });
  }
}

return { trends: trends };

const aiResponse = $json;
const responseData = JSON.parse(aiResponse.choices[0].message.content);

// Process and clean content
const processedContents = responseData.contents.map(content => {
  return {
    trend: content.trend,
    date: new Date().toISOString().split('T')[0],
    linkedin: {
      content: content.linkedin,
      hashtags: extractHashtags(content.linkedin),
      length: content.linkedin.length
    },
    x: {
      content: content.x,
      hashtags: extractHashtags(content.x),
      length: content.x.length
    },
    blog: {
      content: content.blog,
      wordCount: content.blog.split(' ').length,
      readingTime: Math.ceil(content.blog.split(' ').length / 200)
    },
    youtube: {
      title: content.youtube.title,
      hook: content.youtube.hook,
      description: content.youtube.description
    },
    status: 'generated',
    timestamp: new Date().toISOString()
  };
});

function extractHashtags(text) {
  const hashtagRegex = /#[a-zA-Z0-9_]+/g;
  return text.match(hashtagRegex) || [];
}

return { processedContents: processedContents };

